303:                             .rising_glottalized => return 0x00F5, // õ.
304:                             .falling_glottalized => return 0x1ECD, // ọ.
305:                         }
306:                     },
307:                     .circumflex => {
308:                         switch (self.tone) {
309:                             .level => return 0x00F4, // ô.
310:                             .rising => return 0x1ED1, // ố.
311:                             .falling => return 0x1ED3, // ồ.
