324:                             .falling_glottalized => return 0x1EE3, // ợ.
325:                         }
326:                     },
327:                     .breve, .stroke => unreachable,
328:                 }
329:             },
330:             'O' => {
331:                 switch (self.diacritic) {
332:                     .empty => {
333:                         switch (self.tone) {
334:                             .level => unreachable,
