361:                     },
362:                     .breve, .stroke => unreachable,
363:                 }
364:             },
365:             'u' => {
366:                 switch (self.diacritic) {
367:                     .empty => {
368:                         switch (self.tone) {
369:                             .level => unreachable,
370:                             .rising => return 0x00FA, // ú.
371:                             .falling => return 0x00F9, // ù.
