385:                         }
386:                     },
387:                     .circumflex, .breve, .stroke => unreachable,
388:                 }
389:             },
390:             'U' => {
391:                 switch (self.diacritic) {
392:                     .empty => {
393:                         switch (self.tone) {
394:                             .level => unreachable,
395:                             .rising => return 0x00DA, // Ú.
