603: const State = struct {
604:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
605:     // longer than 15. The last input is always literal.
606:     buffer_effective: [16]Span,
607:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
608:     // value (255), we will reset the effective buffer and this value.
609:     buffer_length: u8 = 0,
610:     // The previous buffer length before State.add is called, used to calculate synthetic backspaces.
611:     buffer_length_previous: u8 = 0,
612:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
613:     // calculate backspaces and replacement characters.
614:     buffer_modification_index: ?u8 = null,
615:     // Mark the position (inclusive) in buffer_effective where the engine stops Telex processing
616:     // and appends the remaining composition literally. Positions before literal_index were
617:     // processed as Telex, positions on or after literal_index form the "literal tail". null means
618:     // the whole current buffer_effective remains Telex-processable.
619:     literal_index: ?u8 = null,
620: 
621:     // Initialize the State on allocated memory.
622:     fn init(self: *State) void {
623:         self.* = .{
624:             .buffer_effective = undefined,
625:         };
626:     }
627: 
628:     fn add(self: *State, c: u8) void {
629:         // Only allow a-zA-Z.
630:         assert(isAlphabetic(c));
631: 
632:         if (self.literal_index) |literal_index| {
633:             // The literal_index value must be in range null or 0 -> 15 (within buffer_effective)
634:             // because we won't process Vietnamese input outside the buffer_effective and need the
635:             // literal character for replacement composition.
636:             assert(literal_index < self.buffer_effective.len);
637:             // The literal_index value must be less than buffer length.
638:             assert(literal_index < self.buffer_length);
639:         }
640: 
641:         // buffer_length conditions
642:         // 1. must be within buffer_effective length while the whole buffer is Telex-processable.
643:         // 2. could be equal or more than buffer_effective after literal_index starts the literal
644:         //    tail.
645:         assert(self.buffer_length < self.buffer_effective.len or self.literal_index != null);
646: 
647:         // Reset buffer_modification_index to start the new action.
648:         self.buffer_modification_index = null;
649: 
650:         // Keep the buffer_length in buffer_length_previous for synthetic backspace calculation.
651:         self.buffer_length_previous = self.buffer_length;
652: 
653:         switch (c) {
654:             'A', 'a' => {
655:                 if (self.literal_index != null or self.buffer_length == 0) {
656:                     // 1. Append literally when literal_index is set.
657:                     // 2. Append literal because no previous span existed. Continue Vietnamese
658:                     // processing on next input.
659:                     self.append_literal(c);
660:                     // Set modification index to null because we didn't modify any existing span.
661:                     self.buffer_modification_index = null;
662:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .empty)) {
663:                     // 3. Previous span is 'A' or 'a', apply circumflex.
664:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
665:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
666:                     // Set modification index for calculating synthetic backspace.
667:                     self.buffer_modification_index = self.buffer_length - 1;
668:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .breve)) {
669:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
670:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
671:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
672:                     // Set modification index for calculating synthetic backspace.
673:                     self.buffer_modification_index = self.buffer_length - 1;
674:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .circumflex)) {
675:                     // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
676:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
677:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
678:                     // Set modification index for calculating synthetic backspace.
679:                     self.buffer_modification_index = self.buffer_length - 1;
680:                     // Start literal input from this position.
681:                     self.literal_index = self.buffer_length;
682:                     // Append literal 'A' or 'a'.
683:                     self.append_literal(c);
684:                 } else if (!self.buffer_effective_last().equals_ignore_case_diacritic_tone(c)) {
685:                     // 6. Append literal when previous span is not 'A', 'a' and its variants.
686:                     self.append_literal(c);
687:                     // No modification.
688:                     self.buffer_modification_index = null;
689:                 } else {
690:                     unreachable;
691:                 }
692:             },
693:             'C', 'c' => { // fill missing diacritic, e.g. cước.
694:                 if (self.literal_index != null or self.buffer_length < 2) {
695:                     // 1. Append literally when literal_index is set.
696:                     // 2. Append literal because no previous span existed. Continue Vietnamese
697:                     // processing on next input.
698:                     // 3. Buffer is less than 2 characters to start with.
699:                     self.append_literal(c);
700:                     // Set modification index to null because we didn't modify any existing span.
701:                     self.buffer_modification_index = null;
702:                 } else if (self.buffer_effective[self.buffer_length - 2].equals_ignore_case_tone('U', .empty) and self.buffer_effective[self.buffer_length - 1].equals_ignore_case_tone('O', .horn)) {
703:                     // 4. Pattern: 'UƠ', fill missing horn on 'U'.
704:                     const span_previous2 = self.buffer_effective[self.buffer_length - 2];
705:                     self.buffer_effective[self.buffer_length - 2] = Span.init_diacritic_tone(span_previous2.base, .horn, span_previous2.tone);
706:                     self.buffer_modification_index = self.buffer_length - 2;
707:                     // Append the new character literally.
708:                     self.append_literal(c);
709:                 } else if (self.buffer_effective[self.buffer_length - 2].equals_ignore_case_tone('U', .horn) and self.buffer_effective[self.buffer_length - 1].equals_ignore_case_tone('O', .empty)) {
710:                     // 5. Pattern: 'ƯO', fill missing horn on 'O'.
711:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
712:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .horn, span_previous.tone);
713:                     self.buffer_modification_index = self.buffer_length - 1;
714:                     // Append the new character literally.
715:                     self.append_literal(c);
716:                 } else {
717:                     // 6. No pattern matched, append literally.
718:                     self.append_literal(c);
719:                     self.buffer_modification_index = null;
720:                 }
721:             },
722:             'D', 'd' => { // stroke.
723:                 if (self.literal_index != null or self.buffer_length == 0) {
724:                     // 1. Append literally when literal_index is set.
725:                     // 2. Append literal because no previous span existed. Continue Vietnamese
726:                     // processing on next input.
727:                     self.append_literal(c);
728:                     // Set modification index to null because we didn't modify any existing span.
729:                     self.buffer_modification_index = null;
730:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .empty)) {
731:                     // 3. Previous span is 'D' or 'd', apply stroke.
732:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
733:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .stroke, span_previous.tone);
734:                     // Set modification index for calculating synthetic backspace.
735:                     self.buffer_modification_index = self.buffer_length - 1;
736:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .stroke)) {
737:                     // 4. Previous span is 'Đ' or 'đ', cancel stroke for previous span and append new literal span.
738:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
739:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
740:                     // Set modification index for calculating synthetic backspace.
741:                     self.buffer_modification_index = self.buffer_length - 1;
742:                     // Start literal input from this position.
743:                     self.literal_index = self.buffer_length;
744:                     // Append literal 'D' or 'd'.
745:                     self.append_literal(c);
746:                 } else if (!self.buffer_effective_last().equals_ignore_case_diacritic_tone(c)) {
747:                     // 5. Append literal when previous span is not 'D', 'd' and its variants.
748:                     self.append_literal(c);
749:                     // No modification.
750:                     self.buffer_modification_index = null;
751:                 } else {
752:                     unreachable;
753:                 }
754:             },
755:             'E', 'e' => {
